type Ohaeng = "목" | "화" | "토" | "금" | "수";

function getOhaeng(birthYear: number): Ohaeng {
  const arr: Ohaeng[] = ["목","목","화","화","토","토","금","금","수","수"];
  return arr[((birthYear - 4) % 10 + 10) % 10];
}

function fill(text: string, name: string, other: string = "그 사람", pet: string = "반려동물") {
  return text
    .replace(/\{\{name\}\}/g, name)
    .replace(/\{\{other\}\}/g, other)
    .replace(/\{\{pet\}\}/g, pet);
}

